def loadclass(module_and_name):
name=''
while True:
    try:
        module, n = module_and_name.rsplit('.', 1)
        name = n + ('.' if len(name) > 0 else '') + name  
    except:
        return None
    try:
        module = util.untranslate_module_name(module)
        __import__(module)
        return getattr(sys.modules[module], name)
    except:
        continue

